INSERT OR IGNORE INTO dictionary (keyword, slug, classic_meaning, psychological_meaning, created_at) VALUES
('deniz', 'deniz', 'Rüyada deniz görmek; geniş rızka, devlete ve büyük bir makama işaret eder. Sakin deniz huzur, dalgalı deniz ise zorlu bir dönem habercisidir.', 'Deniz bilinçaltının sonsuzluğunu ve duygusal derinliği simgeler. Sakin deniz iç huzuru, fırtınalı deniz bastırılmış duyguları yansıtabilir.', unixepoch()),
('agac', 'agac', 'Rüyada ağaç görmek; köklü bir aileye, uzun ömre ve berekete işaret eder. Meyveli ağaç hayır ve kazançtır.', 'Ağaç büyümeyi, kişisel gelişimi ve hayatın farklı evrelerini temsil eder. Kökler geçmişi, dallar geleceği simgeler.', unixepoch()),
('bebek-aglamasi', 'bebek-aglamasi', 'Rüyada ağlayan bebek görmek; çözülmesi gereken bir mesele ya da ilgi bekleyen bir konuya işaret eder.', 'Ağlayan bebek, ihmal edilen bir ihtiyacı veya bakıma muhtaç bir iç dünyayı simgeleyebilir.', unixepoch()),
('kus', 'kus', 'Rüyada kuş görmek; müjde, haber ve özgürlüğe işaret eder. Beyaz kuş hayır, siyah kuş dikkatli olmayı gerektirir.', 'Kuş özgürlük arzusunu, ruhsal yükselişi ve düşüncelerin uçuşunu temsil eder.', unixepoch()),
('at', 'at', 'Rüyada at görmek; şeref, makam ve güçlü bir desteğe işaret eder. Ata binmek mertebenin yükselmesidir.', 'At içsel gücü, tutkuyu ve kontrol edilen enerjiyi simgeler.', unixepoch()),
('balik', 'balik', 'Rüyada balık görmek; rızık, kazanç ve bereket olarak yorumlanır. Taze balık helal kazanç, çok balık bolluktur.', 'Balık bilinçaltından gelen sezgileri ve henüz fark edilmemiş fırsatları temsil eder.', unixepoch()),
('altin', 'altin', 'Rüyada altın görmek bazı tabircilere göre dünyalık sıkıntı, bazılarına göre değerli bir kazanç olarak yorumlanır. Kadın için süs ve sevinçtir.', 'Altın öz değeri, içsel zenginliği ve gerçek potansiyeli simgeler.', unixepoch()),
('bina', 'bina', 'Rüyada yüksek bina görmek; hedeflere, kariyere ve sağlam temellere işaret eder.', 'Bina kişinin hayatta kurduğu yapıyı, kariyerini ve benlik inşasını temsil eder.', unixepoch()),
('yangin', 'yangin', 'Rüyada yangın görmek; öfke, kavga ya da büyük bir değişime işaret eder. Söndürülen yangın sıkıntının geçmesidir.', 'Yangın kontrolden çıkan duyguları, tükenmişliği ya da köklü bir dönüşümü simgeler.', unixepoch()),
('bicak', 'bicak', 'Rüyada bıçak görmek; söze, tartışmaya ya da bir kararın keskinliğine işaret eder.', 'Bıçak ayrılığı, net sınırlar koyma ihtiyacını veya içsel bir çatışmayı temsil edebilir.', unixepoch()),
('cocuk', 'cocuk', 'Rüyada çocuk görmek; sevinç, yeni başlangıçlar ve masumiyete işaret eder.', 'Çocuk iç çocuğu, oyunculuğu ve henüz gelişen yönleri simgeler.', unixepoch()),
('dugun', 'dugun', 'Rüyada düğün görmek; bazı tabirlerde sevince ve birlikteliğe, bazılarında ise sorumluluğa işaret eder.', 'Düğün bir birleşmeyi, hayatın iki yönünün uyumunu veya yeni bir bağlılığı temsil eder.', unixepoch()),
('mezar', 'mezar', 'Rüyada mezar görmek; tövbe, geçmişle yüzleşme ve uzun ömür olarak yorumlanır; korkulacak bir işaret değildir.', 'Mezar geçmişin kapanışını, bir dönemin sonlanmasını ve yeni başlangıca yer açmayı simgeler.', unixepoch()),
('kan', 'kan', 'Rüyada kan görmek; mal, haram-helal kazanç ya da akrabalık bağına işaret eder. Yoruma temas detayı yön verir.', 'Kan yaşam enerjisini, tutkuyu ve bazen kaybedilen gücü temsil eder.', unixepoch()),
('sac', 'sac', 'Rüyada saç görmek; uzun saç mal ve uzun ömür, saç kesmek ise sıkıntıdan kurtulmak olarak yorumlanır.', 'Saç kişisel gücü, kimliği ve özgüveni simgeler. Saç kaybı kontrol kaygısını yansıtabilir.', unixepoch()),
('yagmur', 'yagmur', 'Rüyada yağmur görmek; rahmet, bereket ve sıkıntıların ardından gelen ferahlığa işaret eder.', 'Yağmur arınmayı, duygusal boşalmayı ve yenilenmeyi temsil eder.', unixepoch()),
('uckmak-dusmek', 'dusmek', 'Rüyada düşmek; bir mevkiden veya durumdan endişe duymaya işaret eder. Düşüp zarar görmemek sıkıntının atlatılmasıdır.', 'Düşmek kontrol kaybı korkusunu, güvensizliği veya hayatta bir destek arayışını simgeler.', unixepoch()),
('aglama', 'aglama', 'Rüyada ağlamak; çoğu tabirde sevince ve ferahlığa işaret eder; gözyaşı sıkıntının dışarı atılmasıdır.', 'Ağlamak bastırılmış duyguların serbest kalmasını ve duygusal arınmayı temsil eder.', unixepoch()),
('gulmek', 'gulmek', 'Rüyada gülmek; bazı tabirlerde sevince, bazılarında ise dikkatli olunması gereken bir duruma işaret eder.', 'Gülmek içsel neşeyi, rahatlamayı veya bazen gerginliği örten bir tepkiyi simgeler.', unixepoch()),
('kedi', 'kedi', 'Rüyada kedi görmek; bazı tabirlerde hırsıza ya da hilekar bir kişiye işaret eder; uysal kedi ise dosttur.', 'Kedi bağımsızlığı, dişil enerjiyi ve sezgileri temsil eder.', unixepoch()),
('aslan', 'aslan', 'Rüyada aslan görmek; güçlü bir kişiye, otoriteye veya saygın bir makama işaret eder.', 'Aslan içsel gücü, liderliği ve cesareti simgeler. Korkulan aslan, yüzleşilmemiş bir gücü gösterebilir.', unixepoch()),
('yol', 'yol', 'Rüyada yol görmek; hayat yolculuğuna, alınacak kararlara ve geleceğe işaret eder. Düz yol kolaylık, dolambaçlı yol zorluktur.', 'Yol hayatın gidişatını, seçimleri ve kişisel yolculuğu temsil eder.', unixepoch()),
('kapi', 'kapi', 'Rüyada kapı görmek; yeni fırsatlara, açılan ya da kapanan imkanlara işaret eder. Açık kapı hayırlı yoldur.', 'Kapı yeni bir aşamaya geçişi, fırsatları veya kapatılması gereken bir dönemi simgeler.', unixepoch()),
('ayna', 'ayna', 'Rüyada ayna görmek; kişinin kendi haline, itibarına ve içyüzüne bakmasına işaret eder.', 'Ayna öz farkındalığı, kendini görme ve kimlik sorgulamasını temsil eder.', unixepoch()),
('gelinlik', 'gelinlik', 'Rüyada gelinlik görmek; bekarlar için evlilik, evliler için sevinçli bir habere işaret edebilir.', 'Gelinlik yeni bir başlangıcı, dönüşümü ve bir rolün üstlenilmesini simgeler.', unixepoch()),
('para-bulmak', 'para-bulmak', 'Rüyada para bulmak; beklenmedik bir kazanca ya da bir sıkıntının çözülmesine işaret eder.', 'Para bulmak fark edilmemiş bir iç değeri veya yeni bir öz güven kaynağını temsil edebilir.', unixepoch()),
('hamilelik', 'hamilelik', 'Rüyada hamile olmak; yeni bir başlangıca, bereketli bir projeye ya da hayırlı bir habere işaret eder.', 'Hamilelik yeni bir fikrin, projenin veya kişisel gelişimin olgunlaşmasını simgeler.', unixepoch()),
('telefon', 'telefon', 'Rüyada telefon görmek; bir haber, iletişim ya da uzaktan gelecek bir gelişmeye işaret eder.', 'Telefon iletişim ihtiyacını, bağ kurma arzusunu veya beklenen bir mesajı temsil eder.', unixepoch()),
('okul', 'okul', 'Rüyada okul görmek; öğrenme, gelişme ve hayat dersleri çıkarmaya işaret eder.', 'Okul kişisel gelişimi, sınanma duygusunu ve geçmiş deneyimlerden öğrenmeyi simgeler.', unixepoch()),
('namaz', 'namaz', 'Rüyada namaz kılmak; huzur, dileklerin kabulü ve manevi bir doyuma işaret eder.', 'İbadet etmek iç huzur arayışını, anlam ihtiyacını ve kendini bütün hissetme isteğini temsil eder.', unixepoch());
